def solve(grid):
    if not grid: return []
    def is_leaf(r, c, length):
        for i in range(r, r + length):
            for j in range(c, c + length):
                if grid[i][j] != grid[r][c]: return False
        return True
    def helper(r, c, length):
        if is_leaf(r, c, length):
            return [1, grid[r][c]] # isLeaf, val
        half = length // 2
        topLeft = helper(r, c, half)
        topRight = helper(r, c + half, half)
        bottomLeft = helper(r + half, c, half)
        bottomRight = helper(r + half, c + half, half)
        return [0, 1] + topLeft + topRight + bottomLeft + bottomRight
    return helper(0, 0, len(grid))

